# Check actual symbols near the problematic addresses using nm
# Sort by address and find surrounding symbols for 0x2f4b20 and 0x2f4c84
nm -C /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -v ' \$[dtx]' | sort | awk '
/^00000000002f4/ { print }
/^00000000002f3/ { last=$0 }
/^00000000002f5/ && !printed { print last; print; printed=1 }
' | head -20

echo "==="
# Also try finding the function containing 0x2f4b20
nm -C -S /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -v ' \$[dtx]' | sort | awk -v addr=0x2f4b20 '
BEGIN { target=strtonum(addr) }
{
  a=strtonum("0x"$1)
  if ($2 != "") s=strtonum("0x"$2); else s=0
  if (a <= target && (s==0 || a+s > target)) print
  if (a > target && !found) { found=1; print "NEXT: "$0 }
}' | tail -5

